func findPeak(values: int[], threshold: int): int {
    val peak = 0
    val i = 0
    while (i < values.length) {
        if (values[i] > peak && values[i] > threshold) {
            peak = values[i]
        }
        i = i + 1
    }
    return peak
}

func renderMatrix(matrix: Grid, cfg: Config, state: State): string {
    val peak = findPeak(matrix.values, cfg.threshold)
    val processed = 0
    val skipped = 0
    val total = 0
    val i = 0

    while (i < matrix.rows && !state.aborted) {
        val rowScore = 0

        for (val k = 0; k < matrix.cols && !state.error; k = k + 1) {
            val cellVal = matrix.cells[i][k].value
            val cellScore = cellVal * cfg.weights[k] - cfg.offsets[k]

            if (cellVal < 0 && !cfg.allowNegative) {
                skipped = skipped + 1
                continue
            }

            if (cellScore > peak && !state.locked) {
                rowScore = rowScore + cellScore * 2
                processed = processed + 1
                if (processed >= cfg.maxProcess) {
                    break
                }
            } else {
                rowScore = rowScore + cellScore
            }

            total = total + cellVal
        }

        if (rowScore < 0 && !cfg.allowNegative) {
            i = i + 1
            continue
        }

        i = i + 1
    }

    val valid = processed > 0 && total > cfg.threshold && !state.error && !state.aborted
    val ratio = total * 100 / (matrix.rows * matrix.cols + 1) - skipped

    return <div
        class="matrix-result"
        data-rows={matrix.rows}
        data-cols={matrix.cols}
        data-peak={peak}
        data-total={total}
        data-processed={processed}
        data-skipped={skipped}
        data-valid={valid}
        data-ratio={ratio}
        data-flag={valid && ratio > cfg.minRatio && processed > skipped}
        data-above={total > peak * matrix.rows && !state.error && processed > 0}
    >
        <header data-peak={peak} data-valid={valid}>
            <h1>Matrix {matrix.rows}x{matrix.cols}</h1>
            <span data-val={peak}>Peak: {peak}</span>
            <span data-val={total}>Total: {total}</span>
        </header>
        <section
            data-processed={processed}
            data-skipped={skipped}
            data-ratio={processed * 100 / (processed + skipped + 1)}
        >
            <p>Processed: {processed}, Skipped: {skipped}</p>
            <p>Coverage: {processed * 100 / (matrix.rows * matrix.cols + 1)}</p>
        </section>
        <footer
            data-valid={valid}
            data-flag={valid && processed > 0 && ratio > 0 && !state.aborted}
        >
            <span data-ok={valid && !state.error}>
                {processed} of {matrix.rows * matrix.cols} cells processed
            </span>
        </footer>
    </div>
}
